import React, { useState, useEffect, useMemo, useRef } from 'react';
import { 
  LayoutDashboard, Building2, BedDouble, Calendar, Star, 
  LogOut, Plus, Edit2, Trash2, X, ChevronLeft, Users, 
  MapPin, Phone, Mail, Search, Filter, DollarSign, 
  TrendingUp, AlertCircle, Check, Image as ImageIcon,
  Wifi, Car, Coffee, Waves, Dumbbell, Sparkles, Wind,
  Thermometer, Tv, Music, UtensilsCrossed, Wine, PawPrint,
  Baby, Accessibility, Briefcase, Clock, Shield, MessageSquare,
  ThumbsUp, Flag, Eye, User, Download, FileText, BarChart3
} from 'lucide-react';
import { getHotels, deleteHotel, addReview } from './services/hotelService';
import { getHotelRooms, getAllRooms, getRoom, deleteRoom } from './services/roomService';
import { getMyBookings, cancelBooking, deleteBooking } from './services/bookingService';
import api from './services/api';
import Swal from 'sweetalert2';
// ✅ PDF Libraries
import { jsPDF } from 'jspdf';
import autoTable from 'jspdf-autotable';

// ... (keep all existing constants: HOTEL_AMENITIES, ROOM_TYPES, GUEST_OPTIONS)

// ✅ REPORT MODAL COMPONENT
const ReportModal = ({ isOpen, onClose, hotels, rooms, bookings, stats }) => {
  const [reportType, setReportType] = useState('summary');
  const [dateRange, setDateRange] = useState('all');
  const [generating, setGenerating] = useState(false);

  if (!isOpen) return null;

  const generatePDF = async () => {
    setGenerating(true);
    
    try {
      const doc = new jsPDF({ orientation: 'portrait', unit: 'mm', format: 'a4' });
      const pageWidth = doc.internal.pageSize.getWidth();
      const margin = 15;
      let yPos = 20;

      // === HEADER ===
      doc.setFillColor(15, 23, 42); // slate-950
      doc.rect(0, 0, pageWidth, 35, 'F');
      
      doc.setTextColor(34, 211, 238); // cyan-400
      doc.setFontSize(22);
      doc.setFont('helvetica', 'bold');
      doc.text('AI STAY', margin, 18);
      
      doc.setTextColor(255, 255, 255);
      doc.setFontSize(12);
      doc.setFont('helvetica', 'normal');
      doc.text('Admin Dashboard Report', margin, 26);
      
      doc.setTextColor(156, 163, 175); // gray-400
      doc.setFontSize(9);
      doc.text(`Generated: ${new Date().toLocaleString()}`, margin, 32);
      
      yPos = 45;

      // === REPORT TYPE: SUMMARY ===
      if (reportType === 'summary' || reportType === 'all') {
        doc.setTextColor(34, 211, 238);
        doc.setFontSize(16);
        doc.setFont('helvetica', 'bold');
        doc.text('Executive Summary', margin, yPos);
        yPos += 8;

        // Stats cards as table
        autoTable(doc, {
          startY: yPos,
          head: [['Metric', 'Value']],
          body: [
            ['Total Hotels', stats.totalHotels.toString()],
            ['Total Rooms', stats.totalRooms.toString()],
            ['Total Bookings', stats.totalBookings.toString()],
            ['Total Revenue', `₱${stats.totalRevenue.toLocaleString()}`],
            ['Total Reviews', stats.totalReviews.toString()],
            ['Average Rating', `${stats.averageRating}★`],
            ['Confirmed Bookings', stats.confirmedBookings.toString()],
            ['Cancelled Bookings', stats.cancelledBookings.toString()],
          ],
          theme: 'grid',
          headStyles: { 
            fillColor: [6, 182, 212], // cyan-500
            textColor: [255, 255, 255],
            fontStyle: 'bold'
          },
          bodyStyles: { 
            fillColor: [30, 41, 59], // slate-800
            textColor: [255, 255, 255]
          },
          alternateRowStyles: {
            fillColor: [15, 23, 42], // slate-950
          },
          styles: { fontSize: 10, cellPadding: 4 },
          margin: { left: margin, right: margin }
        });
        yPos = doc.lastAutoTable.finalY + 10;
      }

      // === REPORT TYPE: HOTELS ===
      if (reportType === 'hotels' || reportType === 'all') {
        if (yPos > 250) { doc.addPage(); yPos = 20; }
        
        doc.setTextColor(34, 211, 238);
        doc.setFontSize(16);
        doc.setFont('helvetica', 'bold');
        doc.text('Hotels Directory', margin, yPos);
        yPos += 8;

        const hotelData = hotels.map(h => [
          h.name,
          `${h.location.city}, ${h.location.country}`,
          `${h.starRating}★`,
          h.roomCount || 0,
          h.averageRating || h.starRating,
          h.reviewCount || 0,
          `₱${(h.starRating * 500).toLocaleString()}`
        ]);

        autoTable(doc, {
          startY: yPos,
          head: [['Hotel Name', 'Location', 'Rating', 'Rooms', 'Avg Score', 'Reviews', 'Price/Night']],
          body: hotelData,
          theme: 'grid',
          headStyles: { 
            fillColor: [6, 182, 212],
            textColor: [255, 255, 255],
            fontStyle: 'bold'
          },
          bodyStyles: { 
            fillColor: [30, 41, 59],
            textColor: [255, 255, 255]
          },
          alternateRowStyles: { fillColor: [15, 23, 42] },
          styles: { fontSize: 9, cellPadding: 3 },
          margin: { left: margin, right: margin }
        });
        yPos = doc.lastAutoTable.finalY + 10;
      }

      // === REPORT TYPE: BOOKINGS ===
      if (reportType === 'bookings' || reportType === 'all') {
        if (yPos > 220) { doc.addPage(); yPos = 20; }
        
        doc.setTextColor(34, 211, 238);
        doc.setFontSize(16);
        doc.setFont('helvetica', 'bold');
        doc.text('Booking Records', margin, yPos);
        yPos += 8;

        const bookingData = bookings.map(b => {
          const nights = Math.ceil((new Date(b.checkOutDate) - new Date(b.checkInDate)) / (1000 * 60 * 60 * 24));
          return [
            b.hotel?.name || 'N/A',
            b.user?.name || 'Guest',
            new Date(b.checkInDate).toLocaleDateString(),
            new Date(b.checkOutDate).toLocaleDateString(),
            nights.toString(),
            b.guests.toString(),
            `₱${b.totalPrice.toLocaleString()}`,
            b.status.toUpperCase()
          ];
        });

        autoTable(doc, {
          startY: yPos,
          head: [['Hotel', 'Guest', 'Check-in', 'Check-out', 'Nights', 'Guests', 'Total', 'Status']],
          body: bookingData,
          theme: 'grid',
          headStyles: { 
            fillColor: [6, 182, 212],
            textColor: [255, 255, 255],
            fontStyle: 'bold'
          },
          bodyStyles: { 
            fillColor: [30, 41, 59],
            textColor: [255, 255, 255]
          },
          alternateRowStyles: { fillColor: [15, 23, 42] },
          styles: { fontSize: 8, cellPadding: 3 },
          margin: { left: margin, right: margin },
          didParseCell: (data) => {
            if (data.column.index === 7) {
              const status = data.cell.raw;
              if (status === 'CONFIRMED') {
                data.cell.styles.textColor = [34, 197, 94]; // green
              } else if (status === 'CANCELLED') {
                data.cell.styles.textColor = [239, 68, 68]; // red
              }
            }
          }
        });
        yPos = doc.lastAutoTable.finalY + 10;
      }

      // === REPORT TYPE: REVENUE ===
      if (reportType === 'revenue' || reportType === 'all') {
        if (yPos > 220) { doc.addPage(); yPos = 20; }
        
        doc.setTextColor(34, 211, 238);
        doc.setFontSize(16);
        doc.setFont('helvetica', 'bold');
        doc.text('Revenue Analysis', margin, yPos);
        yPos += 8;

        const revenueByHotel = {};
        bookings.filter(b => b.status === 'confirmed').forEach(b => {
          const name = b.hotel?.name || 'Unknown';
          revenueByHotel[name] = (revenueByHotel[name] || 0) + b.totalPrice;
        });

        const revenueData = Object.entries(revenueByHotel)
          .sort((a, b) => b[1] - a[1])
          .map(([name, amount]) => [name, `₱${amount.toLocaleString()}`]);

        autoTable(doc, {
          startY: yPos,
          head: [['Hotel', 'Revenue']],
          body: revenueData,
          theme: 'grid',
          headStyles: { 
            fillColor: [6, 182, 212],
            textColor: [255, 255, 255],
            fontStyle: 'bold'
          },
          bodyStyles: { 
            fillColor: [30, 41, 59],
            textColor: [255, 255, 255]
          },
          alternateRowStyles: { fillColor: [15, 23, 42] },
          styles: { fontSize: 10, cellPadding: 4 },
          margin: { left: margin, right: margin }
        });
        yPos = doc.lastAutoTable.finalY + 10;
      }

      // === FOOTER ===
      const totalPages = doc.getNumberOfPages();
      for (let i = 1; i <= totalPages; i++) {
        doc.setPage(i);
        doc.setTextColor(100, 116, 139);
        doc.setFontSize(8);
        doc.text(`Page ${i} of ${totalPages}`, pageWidth / 2, 287, { align: 'center' });
        doc.text('AI STAY Admin Dashboard • Confidential', margin, 287);
      }

      // Save
      const timestamp = new Date().toISOString().split('T')[0];
      doc.save(`AI-STAY-Report-${reportType}-${timestamp}.pdf`);
      
      Swal.fire({
        icon: 'success',
        title: 'Report Generated!',
        text: `Your ${reportType} report has been downloaded.`,
        timer: 2000,
        showConfirmButton: false
      });
      
    } catch (err) {
      console.error('PDF generation failed:', err);
      Swal.fire({
        icon: 'error',
        title: 'Generation Failed',
        text: 'Could not generate PDF report. Please try again.'
      });
    } finally {
      setGenerating(false);
      onClose();
    }
  };

  return (
    <div className="fixed inset-0 z-[10001] flex items-center justify-center bg-black/80 backdrop-blur-sm p-4">
      <div className="bg-slate-900 rounded-3xl p-8 max-w-lg w-full border border-white/10 shadow-2xl">
        <div className="flex justify-between items-center mb-6">
          <div className="flex items-center gap-3">
            <div className="w-10 h-10 rounded-xl bg-gradient-to-r from-cyan-500 to-purple-500 flex items-center justify-center">
              <FileText className="w-5 h-5 text-white" />
            </div>
            <div>
              <h3 className="text-xl font-bold">Generate Report</h3>
              <p className="text-gray-400 text-sm">Export dashboard data to PDF</p>
            </div>
          </div>
          <button onClick={onClose} className="p-2 hover:bg-white/10 rounded-lg transition-colors">
            <X className="w-5 h-5" />
          </button>
        </div>

        <div className="space-y-5">
          {/* Report Type */}
          <div>
            <label className="block text-sm text-gray-400 mb-2">Report Type</label>
            <div className="grid grid-cols-2 gap-2">
              {[
                { value: 'summary', label: 'Summary', icon: BarChart3 },
                { value: 'hotels', label: 'Hotels', icon: Building2 },
                { value: 'bookings', label: 'Bookings', icon: Calendar },
                { value: 'revenue', label: 'Revenue', icon: DollarSign },
                { value: 'all', label: 'Complete Report', icon: FileText },
              ].map(({ value, label, icon: Icon }) => (
                <button
                  key={value}
                  onClick={() => setReportType(value)}
                  className={`flex items-center gap-2 px-4 py-3 rounded-xl border transition-all ${
                    reportType === value
                      ? 'bg-cyan-500/20 border-cyan-500/50 text-cyan-400'
                      : 'bg-white/5 border-white/10 text-gray-400 hover:bg-white/10'
                  }`}
                >
                  <Icon className="w-4 h-4" />
                  <span className="text-sm font-medium">{label}</span>
                </button>
              ))}
            </div>
          </div>

          {/* Date Range */}
          <div>
            <label className="block text-sm text-gray-400 mb-2">Date Range</label>
            <select
              value={dateRange}
              onChange={(e) => setDateRange(e.target.value)}
              className="w-full p-3 bg-slate-800 border border-white/10 rounded-xl text-white focus:border-cyan-500/50 focus:outline-none"
            >
              <option value="all">All Time</option>
              <option value="today">Today</option>
              <option value="week">This Week</option>
              <option value="month">This Month</option>
              <option value="year">This Year</option>
            </select>
          </div>

          {/* Preview */}
          <div className="bg-white/5 rounded-xl p-4 border border-white/10">
            <p className="text-xs text-gray-500 uppercase tracking-wider mb-2">Preview</p>
            <div className="space-y-2 text-sm text-gray-300">
              <div className="flex justify-between">
                <span>Hotels:</span>
                <span className="text-cyan-400 font-medium">{hotels.length}</span>
              </div>
              <div className="flex justify-between">
                <span>Rooms:</span>
                <span className="text-cyan-400 font-medium">{rooms.length}</span>
              </div>
              <div className="flex justify-between">
                <span>Bookings:</span>
                <span className="text-cyan-400 font-medium">{bookings.length}</span>
              </div>
              <div className="flex justify-between">
                <span>Revenue:</span>
                <span className="text-green-400 font-medium">₱{stats.totalRevenue.toLocaleString()}</span>
              </div>
            </div>
          </div>

          {/* Actions */}
          <div className="flex gap-3 pt-2">
            <button
              onClick={onClose}
              className="flex-1 py-3 bg-white/10 rounded-xl font-medium hover:bg-white/20 transition-colors"
            >
              Cancel
            </button>
            <button
              onClick={generatePDF}
              disabled={generating}
              className="flex-1 py-3 bg-gradient-to-r from-cyan-500 to-purple-500 rounded-xl font-medium hover:shadow-lg transition-all disabled:opacity-50 flex items-center justify-center gap-2"
            >
              {generating ? (
                <>
                  <div className="w-4 h-4 border-2 border-white/30 border-t-white rounded-full animate-spin" />
                  Generating...
                </>
              ) : (
                <>
                  <Download className="w-4 h-4" />
                  Generate PDF
                </>
              )}
            </button>
          </div>
        </div>
      </div>
    </div>
  );
};

// ... (keep all existing components: AlertModal, HotelModal, RoomModal, ReviewsModal)

const AdminDashboard = ({ user, onLogout }) => {
  // ... (keep all existing state)
  
  // ✅ ADD: Report modal state
  const [showReportModal, setShowReportModal] = useState(false);

  // ... (keep all existing functions: fetchData, showAlert, closeAlert, etc.)

  // ✅ ADD: Quick export functions for each view
  const exportHotelsPDF = () => {
    const doc = new jsPDF();
    doc.setTextColor(34, 211, 238);
    doc.setFontSize(20);
    doc.text('Hotels Directory', 14, 20);
    
    autoTable(doc, {
      startY: 30,
      head: [['Name', 'Location', 'Stars', 'Rooms', 'Rating', 'Reviews']],
      body: hotels.map(h => [
        h.name,
        `${h.location.city}, ${h.location.country}`,
        h.starRating,
        h.roomCount || 0,
        h.averageRating || h.starRating,
        h.reviewCount || 0
      ]),
      theme: 'grid',
      headStyles: { fillColor: [6, 182, 212], textColor: 255 },
      styles: { fontSize: 10 }
    });
    
    doc.save(`hotels-directory-${new Date().toISOString().split('T')[0]}.pdf`);
  };

  const exportBookingsPDF = () => {
    const doc = new jsPDF();
    doc.setTextColor(34, 211, 238);
    doc.setFontSize(20);
    doc.text('Booking Records', 14, 20);
    
    autoTable(doc, {
      startY: 30,
      head: [['Hotel', 'Guest', 'Check-in', 'Check-out', 'Nights', 'Guests', 'Total', 'Status']],
      body: bookings.map(b => {
        const nights = Math.ceil((new Date(b.checkOutDate) - new Date(b.checkInDate)) / (1000 * 60 * 60 * 24));
        return [
          b.hotel?.name || 'N/A',
          b.user?.name || 'Guest',
          new Date(b.checkInDate).toLocaleDateString(),
          new Date(b.checkOutDate).toLocaleDateString(),
          nights,
          b.guests,
          `₱${b.totalPrice.toLocaleString()}`,
          b.status
        ];
      }),
      theme: 'grid',
      headStyles: { fillColor: [6, 182, 212], textColor: 255 },
      styles: { fontSize: 9 }
    });
    
    doc.save(`bookings-report-${new Date().toISOString().split('T')[0]}.pdf`);
  };

  // ... (keep Sidebar, DashboardView, StatCard)

  // ✅ UPDATED: HotelsView with export button
  const HotelsView = () => (
    <div className="space-y-6">
      <div className="flex justify-between items-center">
        <h2 className="text-2xl font-bold">Manage Hotels</h2>
        <div className="flex gap-2">
          <button 
            onClick={exportHotelsPDF}
            className="flex items-center gap-2 px-4 py-2 bg-white/10 rounded-xl font-medium hover:bg-white/20 transition-colors"
          >
            <Download className="w-4 h-4" /> Export PDF
          </button>
          <button 
            onClick={() => { setEditingHotel(null); resetHotelForm(); setShowHotelModal(true); }}
            className="flex items-center gap-2 px-4 py-2 bg-gradient-to-r from-cyan-500 to-purple-500 rounded-xl font-medium hover:shadow-lg transition-all"
          >
            <Plus className="w-5 h-5" /> Add Hotel
          </button>
        </div>
      </div>
      {/* ... rest of HotelsView stays the same */}
    </div>
  );

  // ✅ UPDATED: BookingsView with export button
  const BookingsView = () => (
    <div className="space-y-6">
      <div className="flex justify-between items-center">
        <h2 className="text-2xl font-bold">All Bookings</h2>
        <button 
          onClick={exportBookingsPDF}
          className="flex items-center gap-2 px-4 py-2 bg-white/10 rounded-xl font-medium hover:bg-white/20 transition-colors"
        >
          <Download className="w-4 h-4" /> Export PDF
        </button>
      </div>
      {/* ... rest of BookingsView stays the same */}
    </div>
  );

  // ... (keep RoomsView, ReviewsView)

  // ✅ UPDATED: Sidebar with Generate Report button
  const Sidebar = () => (
    <div className="w-64 bg-slate-900/50 border-r border-white/10 p-6 flex flex-col h-full">
      <div className="flex items-center gap-2 mb-8">
        <Building2 className="w-8 h-8 text-cyan-400" />
        <span className="text-xl font-bold bg-gradient-to-r from-cyan-400 to-purple-400 bg-clip-text text-transparent">Admin Panel</span>
      </div>
      
      <nav className="space-y-2 flex-1">
        {/* ... existing nav items ... */}
        
        {/* ✅ ADD: Generate Report button */}
        <button 
          onClick={() => setShowReportModal(true)}
          className="w-full flex items-center gap-3 px-4 py-3 rounded-xl transition-all duration-300 text-gray-400 hover:bg-white/5 hover:text-white"
        >
          <FileText className="w-5 h-5" />
          <span className="font-medium">Generate Report</span>
        </button>
      </nav>

      {/* ... rest of sidebar */}
    </div>
  );

  // ... (keep all other code)

  // ✅ UPDATED: Main render with ReportModal
  return (
    <div className="min-h-screen bg-slate-950 text-white flex">
      <AlertModal 
        isOpen={alertModal.isOpen} 
        onClose={closeAlert} 
        title={alertModal.title} 
        message={alertModal.message} 
        type={alertModal.type} 
      />
      
      {/* ✅ ADD: Report Modal */}
      <ReportModal
        isOpen={showReportModal}
        onClose={() => setShowReportModal(false)}
        hotels={hotels}
        rooms={rooms}
        bookings={bookings}
        stats={stats}
      />
      
      {/* ... existing modals ... */}
      
      <Sidebar />

      <div className="flex-1 p-8 overflow-y-auto">
        <div className="max-w-7xl mx-auto">
          {/* ... existing tab views ... */}
        </div>
      </div>
    </div>
  );
};

export default AdminDashboard;
